class CustomImageDataset(Dataset):
    """Custom dataset that wraps image folders or synthetic data for demonstration."""

    def __init__(
        self,
        root_dir: Optional[str] = None,
        transform=None,
        num_classes: int = 10,
        num_samples: int = 1000,
        image_size: int = 224,
        use_synthetic: bool = True,
    ):
        self.transform = transform
        self.num_classes = num_classes

        if use_synthetic or root_dir is None:
            logger.info(f"Creating synthetic dataset: {num_samples} samples, {num_classes} classes")
            self.images = torch.randn(num_samples, 3, image_size, image_size)
            self.labels = torch.randint(0, num_classes, (num_samples,))
        else:
            self._load_from_directory(root_dir)

    def _load_from_directory(self, root_dir: str):
        """Load images from a directory structure: root/class_name/image.jpg"""
        from torchvision.datasets import ImageFolder
        dataset = ImageFolder(root_dir, transform=self.transform)
        self.images = []
        self.labels = []
        for img, label in dataset:
            self.images.append(img)
            self.labels.append(label)
        self.images = torch.stack(self.images)
        self.labels = torch.tensor(self.labels)
        self.num_classes = len(dataset.classes)

    def __len__(self):
        return len(self.labels)

    def __getitem__(self, idx):
        image = self.images[idx]
        label = self.labels[idx]
        if self.transform and image.dim() == 3:
            # If transform expects PIL, skip for tensor data
            pass
        return image, label


