class ModelDownloader:
    """Downloads and caches pretrained model checkpoints."""

    def __init__(self, cache_dir: str = "./model_cache"):
        self.cache_dir = Path(cache_dir)
        self.cache_dir.mkdir(parents=True, exist_ok=True)
        logger.info(f"Model cache directory: {self.cache_dir}")

    def download_checkpoint(self, model_name: str) -> str:
        """Download a model checkpoint from URL and return local path."""
        if model_name not in MODEL_REGISTRY:
            raise ValueError(
                f"Model '{model_name}' not found in registry. "
                f"Available models: {list(MODEL_REGISTRY.keys())}"
            )

        config = MODEL_REGISTRY[model_name]
        url = config["url"]
        filename = url.split("/")[-1]
        local_path = self.cache_dir / filename

        if local_path.exists():
            logger.info(f"Checkpoint already cached: {local_path}")
            return str(local_path)

        logger.info(f"Downloading {model_name} from {url}...")
        try:
            state_dict = torch.hub.load_state_dict_from_url(
                url,
                model_dir=str(self.cache_dir),
                map_location="cpu",
                check_hash=True,
            )
            # Save locally
            torch.save(state_dict, local_path)
            logger.info(f"Checkpoint saved to: {local_path}")
            return str(local_path)
        except Exception as e:
            logger.error(f"Failed to download {model_name}: {e}")
            raise

    def download_from_url(self, url: str, filename: Optional[str] = None) -> str:
        """Download a model checkpoint from any URL."""
        if filename is None:
            filename = url.split("/")[-1]
        local_path = self.cache_dir / filename

        if local_path.exists():
            logger.info(f"Checkpoint already cached: {local_path}")
            return str(local_path)

        logger.info(f"Downloading from {url}...")
        state_dict = torch.hub.load_state_dict_from_url(
            url,
            model_dir=str(self.cache_dir),
            map_location="cpu",
        )
        torch.save(state_dict, local_path)
        logger.info(f"Checkpoint saved to: {local_path}")
        return str(local_path)

    def load_checkpoint(self, checkpoint_path: str, device: str = "cpu") -> Dict:
        """Load a checkpoint from local path using torch.load."""
        logger.info(f"Loading checkpoint from: {checkpoint_path}")
        checkpoint = torch.load(checkpoint_path, map_location=device, weights_only=False)
        logger.info(f"Checkpoint loaded. Keys: {list(checkpoint.keys()) if isinstance(checkpoint, dict) else 'state_dict'}")
        return checkpoint

    def list_cached_models(self) -> List[str]:
        """List all cached model files."""
        return [f.name for f in self.cache_dir.iterdir() if f.is_file()]


