class ModelFactory:
    """Creates model architectures and loads pretrained weights."""

    ARCHITECTURE_MAP = {
        "resnet18": models.resnet18,
        "resnet50": models.resnet50,
        "vgg16": models.vgg16,
        "mobilenet_v2": models.mobilenet_v2,
        "efficientnet_b0": models.efficientnet_b0,
        "densenet121": models.densenet121,
    }

    @classmethod
    def create_model(
        cls,
        architecture: str,
        pretrained_weights: Optional[Dict] = None,
        num_classes: int = 1000,
    ) -> nn.Module:
        """Create a model with optional pretrained weights."""
        if architecture not in cls.ARCHITECTURE_MAP:
            raise ValueError(
                f"Unknown architecture '{architecture}'. "
                f"Available: {list(cls.ARCHITECTURE_MAP.keys())}"
            )

        # Create model without pretrained weights
        model = cls.ARCHITECTURE_MAP[architecture](weights=None)

        # Load pretrained weights if provided
        if pretrained_weights is not None:
            try:
                model.load_state_dict(pretrained_weights, strict=True)
                logger.info(f"Loaded pretrained weights for {architecture} (strict)")
            except RuntimeError:
                logger.warning("Strict loading failed, trying non-strict...")
                missing, unexpected = model.load_state_dict(
                    pretrained_weights, strict=False
                )
                if missing:
                    logger.warning(f"Missing keys: {missing[:5]}...")
                if unexpected:
                    logger.warning(f"Unexpected keys: {unexpected[:5]}...")

        # Modify final layer for custom number of classes
        if num_classes != 1000:
            model = cls._modify_classifier(model, architecture, num_classes)

        return model

    @classmethod
    def _modify_classifier(
        cls, model: nn.Module, architecture: str, num_classes: int
    ) -> nn.Module:
        """Replace the final classification layer for transfer learning."""
        if architecture in ["resnet18", "resnet50"]:
            in_features = model.fc.in_features
            model.fc = nn.Linear(in_features, num_classes)
            logger.info(f"Modified ResNet fc: {in_features} -> {num_classes}")

        elif architecture == "vgg16":
            in_features = model.classifier[6].in_features
            model.classifier[6] = nn.Linear(in_features, num_classes)
            logger.info(f"Modified VGG classifier: {in_features} -> {num_classes}")

        elif architecture == "mobilenet_v2":
            in_features = model.classifier[1].in_features
            model.classifier[1] = nn.Linear(in_features, num_classes)
            logger.info(f"Modified MobileNet classifier: {in_features} -> {num_classes}")

        elif architecture == "efficientnet_b0":
            in_features = model.classifier[1].in_features
            model.classifier[1] = nn.Linear(in_features, num_classes)
            logger.info(f"Modified EfficientNet classifier: {in_features} -> {num_classes}")

        elif architecture == "densenet121":
            in_features = model.classifier.in_features
            model.classifier = nn.Linear(in_features, num_classes)
            logger.info(f"Modified DenseNet classifier: {in_features} -> {num_classes}")

        return model


