# Fine-tuning Strategies
# ============================================================================

class FreezingStrategy:
    """Strategies for freezing/unfreezing model layers during fine-tuning."""

    @staticmethod
    def freeze_all_except_classifier(model: nn.Module, architecture: str):
        """Freeze all layers except the final classifier (feature extraction)."""
        # First freeze everything
        for param in model.parameters():
            param.requires_grad = False

        # Unfreeze classifier
        if architecture in ["resnet18", "resnet50"]:
            for param in model.fc.parameters():
                param.requires_grad = True
        elif architecture == "vgg16":
            for param in model.classifier[6].parameters():
                param.requires_grad = True
        elif architecture == "mobilenet_v2":
            for param in model.classifier[1].parameters():
                param.requires_grad = True
        elif architecture == "efficientnet_b0":
            for param in model.classifier[1].parameters():
                param.requires_grad = True
        elif architecture == "densenet121":
            for param in model.classifier.parameters():
                param.requires_grad = True

        trainable = sum(p.numel() for p in model.parameters() if p.requires_grad)
        total = sum(p.numel() for p in model.parameters())
        logger.info(
            f"Frozen strategy: {trainable}/{total} parameters trainable "
            f"({100 * trainable / total:.2f}%)"
        )

    @staticmethod
    def freeze_first_n_layers(model: nn.Module, n: int):
        """Freeze the first n layers of the model."""
        layers = list(model.children())
        for i, layer in enumerate(layers):
            if i < n:
                for param in layer.parameters():
                    param.requires_grad = False

        trainable = sum(p.numel() for p in model.parameters() if p.requires_grad)
        total = sum(p.numel() for p in model.parameters())
        logger.info(
            f"Frozen first {n} layers: {trainable}/{total} parameters trainable "
            f"({100 * trainable / total:.2f}%)"
        )

    @staticmethod
    def gradual_unfreezing(model: nn.Module, epoch: int, total_epochs: int):
        """Gradually unfreeze layers as training progresses."""
        layers = list(model.children())
        num_layers = len(layers)
        # Unfreeze proportional to training progress
        layers_to_unfreeze = int((epoch / total_epochs) * num_layers)

        for param in model.parameters():
            param.requires_grad = False

        for i in range(num_layers - layers_to_unfreeze, num_layers):
            if i >= 0:
                for param in layers[i].parameters():
                    param.requires_grad = True

        trainable = sum(p.numel() for p in model.parameters() if p.requires_grad)
        logger.info(f"Epoch {epoch}: Unfrozen {layers_to_unfreeze}/{num_layers} layers, "
                     f"{trainable} trainable params")


