class FineTuner:
    """Fine-tunes pretrained models on custom datasets."""

    def __init__(
        self,
        model: nn.Module,
        device: str = "auto",
        learning_rate: float = 1e-3,
        weight_decay: float = 1e-4,
        scheduler_step_size: int = 7,
        scheduler_gamma: float = 0.1,
    ):
        if device == "auto":
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        else:
            self.device = torch.device(device)

        self.model = model.to(self.device)
        self.learning_rate = learning_rate
        self.weight_decay = weight_decay

        # Only optimize trainable parameters
        trainable_params = filter(lambda p: p.requires_grad, self.model.parameters())
        self.optimizer = optim.Adam(
            trainable_params, lr=learning_rate, weight_decay=weight_decay
        )
        self.scheduler = optim.lr_scheduler.StepLR(
            self.optimizer, step_size=scheduler_step_size, gamma=scheduler_gamma
        )
        self.criterion = nn.CrossEntropyLoss()

        self.training_history: Dict[str, List[float]] = {
            "train_loss": [],
            "train_acc": [],
            "val_loss": [],
            "val_acc": [],
            "learning_rate": [],
        }

        logger.info(f"FineTuner initialized on device: {self.device}")
        logger.info(f"Trainable parameters: {sum(p.numel() for p in model.parameters() if p.requires_grad):,}")

    def train_epoch(self, dataloader: DataLoader) -> Tuple[float, float]:
        """Train for one epoch."""
        self.model.train()
        running_loss = 0.0
        correct = 0
        total = 0

        for batch_idx, (inputs, targets) in enumerate(dataloader):
            inputs, targets = inputs.to(self.device), targets.to(self.device)

            self.optimizer.zero_grad()
            outputs = self.model(inputs)
            loss = self.criterion(outputs, targets)
            loss.backward()
            self.optimizer.step()

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += targets.size(0)
            correct += predicted.eq(targets).sum().item()

            if (batch_idx + 1) % 10 == 0:
                logger.debug(
                    f"  Batch [{batch_idx + 1}/{len(dataloader)}] "
                    f"Loss: {loss.item():.4f}"
                )

        epoch_loss = running_loss / total
        epoch_acc = 100.0 * correct / total
        return epoch_loss, epoch_acc

    @torch.no_grad()
    def evaluate(self, dataloader: DataLoader) -> Tuple[float, float]:
        """Evaluate the model."""
        self.model.eval()
        running_loss = 0.0
        correct = 0
        total = 0

        for inputs, targets in dataloader:
            inputs, targets = inputs.to(self.device), targets.to(self.device)
            outputs = self.model(inputs)
            loss = self.criterion(outputs, targets)

            running_loss += loss.item() * inputs.size(0)
            _, predicted = outputs.max(1)
            total += targets.size(0)
            correct += predicted.eq(targets).sum().item()

        epoch_loss = running_loss / total
        epoch_acc = 100.0 * correct / total
        return epoch_loss, epoch_acc

    def fit(
        self,
        train_loader: DataLoader,
        val_loader: DataLoader,
        epochs: int = 10,
        save_best: bool = True,
        save_path: str = "./checkpoints",
        use_gradual_unfreezing: bool = False,
        architecture: str = "resnet18",
    ) -> Dict[str, List[float]]:
        """Full training loop with validation."""
        os.makedirs(save_path, exist_ok=True)
        best_val_acc = 0.0
        best_model_path = None

        logger.info(f"Starting fine-tuning for {epochs} epochs...")
        logger.info(f"Train batches: {len(train_loader)}, Val batches: {len(val_loader)}")

        for epoch in range(epochs):
            # Gradual unfreezing if enabled
            if use_gradual_unfreezing:
                FreezingStrategy.gradual_unfreezing(self.model, epoch, epochs)
                # Re-create optimizer with new trainable params
                trainable_params = filter(
                    lambda p: p.requires_grad, self.model.parameters()
                )
                self.optimizer = optim.Adam(
                    trainable_params,
                    lr=self.learning_rate,
                    weight_decay=self.weight_decay,
                )

            # Train
            train_loss, train_acc = self.train_epoch(train_loader)

            # Validate
            val_loss, val_acc = self.evaluate(val_loader)

            # Step scheduler
            self.scheduler.step()
            current_lr = self.optimizer.param_groups[0]["lr"]

            # Record history
            self.training_history["train_loss"].append(train_loss)
            self.training_history["train_acc"].append(train_acc)
            self.training_history["val_loss"].append(val_loss)
            self.training_history["val_acc"].append(val_acc)
            self.training_history["learning_rate"].append(current_lr)

            logger.info(
                f"Epoch [{epoch + 1}/{epochs}] "
                f"Train Loss: {train_loss:.4f} | Train Acc: {train_acc:.2f}% | "
                f"Val Loss: {val_loss:.4f} | Val Acc: {val_acc:.2f}% | "
                f"LR: {current_lr:.6f}"
            )

            # Save best model
            if save_best and val_acc > best_val_acc:
                best_val_acc = val_acc
                best_model_path = os.path.join(
                    save_path, f"best_model_{architecture}.pth"
                )
                self.save_checkpoint(
                    best_model_path,
                    epoch=epoch,
                    val_acc=val_acc,
                    architecture=architecture,
                )
                logger.info(f"  -> New best model saved (Val Acc: {val_acc:.2f}%)")

        # Save final model
        final_path = os.path.join(save_path, f"final_model_{architecture}.pth")
        self.save_checkpoint(
            final_path, epoch=epochs - 1, val_acc=val_acc, architecture=architecture
        )

        logger.info(f"Training complete. Best Val Acc: {best_val_acc:.2f}%")
        if best_model_path:
            logger.info(f"Best model saved at: {best_model_path}")

        return self.training_history

    def save_checkpoint(
        self,
        path: str,
        epoch: int = 0,
        val_acc: float = 0.0,
        architecture: str = "",
    ):
        """Save model checkpoint."""
        checkpoint = {
            "epoch": epoch,
            "model_state_dict": self.model.state_dict(),
            "optimizer_state_dict": self.optimizer.state_dict(),
            "scheduler_state_dict": self.scheduler.state_dict(),
            "val_acc": val_acc,
            "architecture": architecture,
            "training_history": self.training_history,
        }
        torch.save(checkpoint, path)
        logger.info(f"Checkpoint saved: {path}")

    def load_checkpoint(self, path: str):
        """Load model checkpoint."""
        checkpoint = torch.load(path, map_location=self.device, weights_only=False)
        self.model.load_state_dict(checkpoint["model_state_dict"])
        self.optimizer.load_state_dict(checkpoint["optimizer_state_dict"])
        if "scheduler_state_dict" in checkpoint:
            self.scheduler.load_state_dict(checkpoint["scheduler_state_dict"])
        if "training_history" in checkpoint:
            self.training_history = checkpoint["training_history"]
        logger.info(
            f"Checkpoint loaded: epoch={checkpoint.get('epoch', '?')}, "
            f"val_acc={checkpoint.get('val_acc', '?')}"
        )
        return checkpoint


