class TransferLearningPipeline:
    """End-to-end pipeline for transfer learning."""

    def __init__(
        self,
        model_name: str = "resnet18",
        num_classes: int = 10,
        cache_dir: str = "./model_cache",
        checkpoint_dir: str = "./checkpoints",
        freezing_strategy: str = "classifier_only",  # or "gradual", "partial", "full"
        freeze_layers: int = 5,
    ):
        self.model_name = model_name
        self.num_classes = num_classes
        self.cache_dir = cache_dir
        self.checkpoint_dir = checkpoint_dir
        self.freezing_strategy = freezing_strategy
        self.freeze_layers = freeze_layers

        self.downloader = ModelDownloader(cache_dir=cache_dir)
        self.model = None
        self.config = MODEL_REGISTRY.get(model_name, {})
        self.architecture = self.config.get("architecture", model_name)

    def setup_model(self) -> nn.Module:
        """Download and prepare the pretrained model."""
        logger.info(f"=" * 60)
        logger.info(f"Setting up transfer learning pipeline")
        logger.info(f"Model: {self.model_name}, Target classes: {self.num_classes}")
        logger.info(f"=" * 60)

        # Step 1: Download checkpoint
        try:
            checkpoint_path = self.downloader.download_checkpoint(self.model_name)
            # Step 2: Load weights
            weights = self.downloader.load_checkpoint(checkpoint_path)
        except Exception as e:
            logger.warning(f"Could not download pretrained weights: {e}")
            logger.info("Creating model with random initialization...")
            weights = None

        # Step 3: Create model with pretrained weights and modified classifier
        self.model = ModelFactory.create_model(
            architecture=self.architecture,
            pretrained_weights=weights,
            num_classes=self.num_classes,
        )

        # Step 4: Apply freezing strategy
        self._apply_freezing_strategy()

        return self.model

    def _apply_freezing_strategy(self):
        """Apply the selected freezing strategy."""
        if self.freezing_strategy == "classifier_only":
            FreezingStrategy.freeze_all_except_classifier(
                self.model, self.architecture
            )
        elif self.freezing_strategy == "partial":
            FreezingStrategy.freeze_first_n_layers(self.model, self.freeze_layers)
        elif self.freezing_strategy == "full":
            logger.info("Full fine-tuning: all parameters trainable")
        elif self.freezing_strategy == "gradual":
            logger.info("Gradual unfreezing will be applied during training")
            # Initially freeze all except classifier
            FreezingStrategy.freeze_all_except_classifier(
                self.model, self.architecture
            )

    def prepare_data(
        self,
        data_dir: Optional[str] = None,
        batch_size: int = 32,
        num_workers: int = 2,
        val_split: float = 0.2,
        num_samples: int = 500,
        use_synthetic: bool = True,
    ) -> Tuple[DataLoader, DataLoader]:
        """Prepare train and validation data loaders."""
        input_size = self.config.get("input_size", 224)

        transform = transforms.Compose([
            transforms.Resize((input_size, input_size)),
            transforms.RandomHorizontalFlip(),
            transforms.Normalize(
                mean=[0.485, 0.456, 0.406],
                std=[0.229, 0.224, 0.225],
            ),
        ])

        dataset = CustomImageDataset(
            root_dir=data_dir,
            transform=transform,
            num_classes=self.num_classes,
            num_samples=num_samples,
            image_size=input_size,
            use_synthetic=use_synthetic,
        )

        # Split dataset
        val_size = int(len(dataset) * val_split)
        train_size = len(dataset) - val_size
        train_dataset, val_dataset = random_split(dataset, [train_size, val_size])

        train_loader = DataLoader(
            train_dataset,
            batch_size=batch_size,
            shuffle=True,
            num_workers=num_workers,
            pin_memory=True,
        )
        val_loader = DataLoader(
            val_dataset,
            batch_size=batch_size,
            shuffle=False,
            num_workers=num_workers,
            pin_memory=True,
        )

        logger.info(f"Data prepared: {train_size} train, {val_size} val samples")
        return train_loader, val_loader

    def run(
        self,
        data_dir: Optional[str] = None,
        epochs: int = 10,
        batch_size: int = 32,
        learning_rate: float = 1e-3,
        weight_decay: float = 1e-4,
        num_samples: int = 500,
        use_synthetic: bool = True,
    ) -> Dict[str, Any]:
        """Run the complete transfer learning pipeline."""
        # Setup model
        model = self.setup_model()

        # Prepare data
        train_loader, val_loader = self.prepare_data(
            data_dir=data_dir,
            batch_size=batch_size,
            num_samples=num_samples,
            use_synthetic=use_synthetic,
        )

        # Create fine-tuner
        finetuner = FineTuner(
            model=model,
            learning_rate=learning_rate,
            weight_decay=weight_decay,
        )

        # Train
        use_gradual = self.freezing_strategy == "gradual"
        history = finetuner.fit(
            train_loader=train_loader,
            val_loader=val_loader,
            epochs=epochs,
            save_best=True,
            save_path=self.checkpoint_dir,
            use_gradual_unfreezing=use_gradual,
            architecture=self.architecture,
        )

        # Save training report
        report = {
            "model_name": self.model_name,
            "architecture": self.architecture,
            "num_classes": self.num_classes,
            "freezing_strategy": self.freezing_strategy,
            "epochs": epochs,
            "learning_rate": learning_rate,
            "best_val_acc": max(history["val_acc"]) if history["val_acc"] else 0,
            "final_val_acc": history["val_acc"][-1] if history["val_acc"] else 0,
            "final_train_acc": history["train_acc"][-1] if history["train_acc"] else 0,
        }

        report_path = os.path.join(self.checkpoint_dir, "training_report.json")
        with open(report_path, "w") as f:
            json.dump(report, f, indent=2)
        logger.info(f"Training report saved: {report_path}")

        return report


# ============================================================================
# Utility: Load and use a fine-tuned model for inference
# ============================================================================

class ModelInference:
    """Load fine-tuned models and run inference."""

    def __init__(self, checkpoint_path: str, device: str = "auto"):
        if device == "auto":
            self.device = torch.device("cuda" if torch.cuda.is_available() else "cpu")
        else:
            self.device = torch.device(device)

        self.checkpoint_path = checkpoint_path
        self.model = None

    def load(self, num_classes: int = 10):
        """Load a fine-tuned model from checkpoint."""
        checkpoint = torch.load(
            self.checkpoint_path, map_location=self.device, weights_only=False
        )
        architecture = checkpoint.get("architecture", "resnet18")

        self.model = ModelFactory.create_model(
            architecture=architecture,
            num_classes=num_classes,
        )
        self.model.load_state_dict(checkpoint["model_state_dict"])
        self.model.to(self.device)
        self.model.eval()

        logger.info(
            f"Model loaded: {architecture}, epoch={checkpoint.get('epoch')}, "
            f"val_acc={checkpoint.get('val_acc', 'N/A')}"
        )
        return self

    @torch.no_grad()
    def predict(self, images: torch.Tensor) -> Tuple[torch.Tensor, torch.Tensor]:
        """Run inference on images. Returns (predictions, probabilities)."""
        if self.model is None:
            raise RuntimeError("Model not loaded. Call load() first.")

        images = images.to(self.device)
        outputs = self.model(images)
        probabilities = torch.softmax(outputs, dim=1)
        predictions = torch.argmax(probabilities, dim=1)
        return predictions, probabilities


