def main():
    """Demonstrate the full transfer learning pipeline."""

    print("=" * 70)
    print("Transfer Learning Pipeline - Demo")
    print("=" * 70)

    # ---- Example 1: Full pipeline with ResNet18 ----
    print("\n[Pipeline 1] ResNet18 - Classifier Only Fine-tuning")
    print("-" * 50)

    pipeline = TransferLearningPipeline(
        model_name="resnet18",
        num_classes=5,
        cache_dir="./model_cache",
        checkpoint_dir="./checkpoints/resnet18_classifier",
        freezing_strategy="classifier_only",
    )

    report = pipeline.run(
        epochs=3,
        batch_size=16,
        learning_rate=1e-3,
        num_samples=200,
        use_synthetic=True,
    )
    print(f"\nReport: {json.dumps(report, indent=2)}")

    # ---- Example 2: MobileNetV2 with full fine-tuning ----
    print("\n[Pipeline 2] MobileNetV2 - Full Fine-tuning")
    print("-" * 50)

    pipeline2 = TransferLearningPipeline(
        model_name="mobilenet_v2",
        num_classes=3,
        cache_dir="./model_cache",
        checkpoint_dir="./checkpoints/mobilenet_full",
        freezing_strategy="full",
    )

    report2 = pipeline2.run(
        epochs=3,
        batch_size=16,
        learning_rate=1e-4,
        num_samples=200,
        use_synthetic=True,
    )
    print(f"\nReport: {json.dumps(report2, indent=2)}")

    # ---- Example 3: Load fine-tuned model for inference ----
    print("\n[Inference] Loading fine-tuned model")
    print("-" * 50)

    checkpoint_path = "./checkpoints/resnet18_classifier/best_model_resnet18.pth"
    if os.path.exists(checkpoint_path):
        inferencer = ModelInference(checkpoint_path)
        inferencer.load(num_classes=5)

        # Create dummy input
        dummy_input = torch.randn(4, 3, 224, 224)
        predictions, probabilities = inferencer.predict(dummy_input)
        print(f"Predictions: {predictions}")
        print(f"Probabilities shape: {probabilities.shape}")
    else:
        print(f"Checkpoint not found at {checkpoint_path}")

    # ---- Example 4: Manual workflow ----
    print("\n[Manual] Step-by-step workflow")
    print("-" * 50)

    # Download
    downloader = ModelDownloader("./model_cache")
    print(f"Cached models: {downloader.list_cached_models()}")

    try:
        ckpt_path = downloader.download_checkpoint("resnet18")
        weights = downloader.load_checkpoint(ckpt_path)

        # Create and modify model
        model = ModelFactory.create_model(
            architecture="resnet18",
            pretrained_weights=weights,
            num_classes=8,
        )

        # Apply freezing
        FreezingStrategy.freeze_all_except_classifier(model, "resnet18")

        # Quick forward pass test
        test_input = torch.randn(2, 3, 224, 224)
        with torch.no_grad():
            output = model(test_input)
        print(f"Output shape: {output.shape}")
        print("Manual workflow completed successfully!")
    except Exception as e:
        logger.error(f"Manual workflow error: {e}")

    print("\n" + "=" * 70)
    print("Pipeline demo completed!")
    print("=" * 70)


if __name__ == "__main__":
    main()